<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Desktop Environment</title>
    <style>
        :root {
            --bg-color: #2c3e50;
            --accent-color: #e95420; /* Ubuntu Orange */
            --taskbar-bg: rgba(30, 30, 30, 0.9);
            --window-bg: #fdfdfd;
            --header-bg: #3c3c3c;
            --text-color: #333;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; }

        body, html {
            height: 100%;
            overflow: hidden;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #2c3e50 0%, #000000 100%);
            position: relative;
            overflow: hidden;
        }

        /* Taskbar / Dock */
        #taskbar {
            position: absolute;
            bottom: 0;
            width: 100%;
            height: 50px;
            background: var(--taskbar-bg);
            display: flex;
            align-items: center;
            padding: 0 20px;
            gap: 15px;
            border-top: 1px solid #444;
            z-index: 9999;
        }

        #taskbar button {
            padding: 8px 16px;
            background: #444;
            color: white;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            transition: background 0.2s;
        }

        #taskbar button:hover {
            background: var(--accent-color);
        }

        /* Window Styling */
        .window {
            position: absolute;
            min-width: 360px;
            min-height: 240px;
            background: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #999;
        }

        .win-header {
            background: var(--header-bg);
            color: white;
            padding: 8px 12px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            user-select: none;
        }

        .win-close {
            background: #e74c3c;
            border: none;
            color: white;
            padding: 2px 8px;
            border-radius: 3px;
            cursor: pointer;
        }

        .win-content {
            flex: 1;
            padding: 15px;
            overflow: auto;
        }

        /* Files App Styling */
        #files-path {
            margin-bottom: 10px;
            font-weight: bold;
            color: #666;
            border-bottom: 1px solid #ddd;
            padding-bottom: 5px;
        }

        .fs-item {
            padding: 8px;
            cursor: pointer;
            border-radius: 4px;
            transition: background 0.2s;
        }

        .fs-item:hover {
            background: #e0e0e0;
        }

        #files-up {
            margin-bottom: 15px;
            padding: 5px 10px;
            cursor: pointer;
        }

        /* Notepad App Styling */
        #tabs {
            display: flex;
            background: #eee;
            border-bottom: 1px solid #ccc;
            overflow-x: auto;
        }

        .tab {
            padding: 8px 15px;
            background: #ddd;
            border-right: 1px solid #ccc;
            cursor: pointer;
            min-width: 80px;
            text-align: center;
            font-size: 13px;
        }

        .tab.active {
            background: var(--window-bg);
            border-bottom: 2px solid var(--accent-color);
            font-weight: bold;
        }

        #editor {
            width: 100%;
            height: calc(100% - 40px);
            resize: none;
            border: none;
            padding: 10px;
            outline: none;
            font-family: 'Courier New', Courier, monospace;
        }

        #new-tab {
            margin-left: 10px;
            padding: 2px 8px;
            cursor: pointer;
        }
    </style>
</head>
<body>

<div id="desktop">
    <!-- Files Window -->
    <div id="files-window" class="window" style="display: none; top: 100px; left: 100px;">
        <div class="win-header">
            <span>File Explorer</span>
            <button class="win-close">X</button>
        </div>
        <div class="win-content">
            <div id="files-path">/</div>
            <button id="files-up">↑ Up</button>
            <div id="files-list"></div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window" style="display: none; top: 150px; left: 400px;">
        <div class="win-header">
            <span>Notepad</span>
            <button class="win-close">X</button>
        </div>
        <div id="tabs"></div>
        <div class="win-content" style="padding: 0;">
            <textarea id="editor"></textarea>
        </div>
    </div>

    <!-- Taskbar -->
    <div id="taskbar">
        <button id="open-files">Files</button>
        <button id="open-notepad">Notepad</button>
    </div>
</div>

<script>
    /** --- Filesystem Logic --- **/
    const fsData = {
        "root": {
            "bin": {},
            "etc": {},
            "home": {
                "user": {
                    "Documents": {},
                    "Downloads": {},
                    "Pictures": {}
                }
            },
            "usr": {},
            "var": {}
        }
    };

    let currentPath = []; // Array of folder names, e.g., ["home", "user"]

    function getDir(pathArr) {
        let dir = fsData.root;
        for (const part of pathArr) {
            dir = dir[part];
        }
        return dir;
    }

    function renderFiles() {
        const listEl = document.getElementById('files-list');
        const pathEl = document.getElementById('files-path');
        const currentDir = getDir(currentPath);

        // Update Path Display
        let displayPath = "/" + currentPath.join("/");
        pathEl.innerText = displayPath;

        // Clear and Render Items
        listEl.innerHTML = "";
        Object.keys(currentDir).forEach(name => {
            const item = document.createElement('div');
            item.className = 'fs-item';
            item.innerText = name + (typeof currentDir[name] === 'object' ? "/" : "");

            item.addEventListener('dblclick', () => {
                if (typeof currentDir[name] === 'object') {
                    currentPath.push(name);
                    renderFiles();
                }
            });
            listEl.appendChild(item);
        });
    }

    document.getElementById('files-up').addEventListener('click', () => {
        if (currentPath.length > 0) {
            currentPath.pop();
            renderFiles();
        }
    });

    /** --- Notepad Logic --- **/
    let tabs = [];
    let activeTabId = null;

    function initNotepad() {
        const saved = localStorage.getItem('notepad_tabs');
        if (saved) {
            tabs = JSON.parse(saved);
            if (tabs.length > 0) {
                activeTabId = tabs[0].id;
            } else {
                createNewTab();
            }
        } else {
            createNewTab();
        }
        renderTabs();
    }

    function createNewTab() {
        const id = Date.now();
        tabs.push({ id, content: "" });
        activeTabId = id;
        saveNotepad();
        renderTabs();
    }

    function saveNotepad() {
        localStorage.setItem('notepad_tabs', JSON.stringify(tabs));
    }

    function renderTabs() {
        const tabsEl = document.getElementById('tabs');
        tabsEl.innerHTML = "";

        tabs.forEach(tab => {
            const tabBtn = document.createElement('div');
            tabBtn.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
            tabBtn.innerText = `Tab ${tabs.indexOf(tab) + 1}`;
            tabBtn.onclick = () => {
                activeTabId = tab.id;
                renderTabs();
                updateEditor();
            };
            tabsEl.appendChild(tabBtn);
        });

        const newBtn = document.createElement('button');
        newBtn.id = "new-tab";
        newBtn.innerText = "+";
        newBtn.onclick = createNewTab;
        tabsEl.appendChild(newBtn);

        updateEditor();
    }

    function updateEditor() {
        const editor = document.getElementById('editor');
        const activeTab = tabs.find(t => t.id === activeTabId);
        if (activeTab) {
            editor.value = activeTab.content;
        }
    }

    // Sync input to state and storage
    document.getElementById('editor').addEventListener('input', (e) => {
        const activeTab = tabs.find(t => t.id === activeTabId);
        if (activeTab) {
            activeTab.content = e.target.value;
            saveNotepad();
        }
    });

    /** --- Window Management --- **/
    function toggleWindow(id, show) {
        const win = document.getElementById(id);
        win.style.display = show ? "flex" : "none";
    }

    document.getElementById('open-files').onclick = () => {
        currentPath = []; // Reset to root when opening
        renderFiles();
        toggleWindow('files-window', true);
    };

    document.getElementById('open-notepad').onclick = () => {
        initNotepad();
        toggleWindow('notepad-window', true);
    };

    document.querySelectorAll('.win-close').forEach(btn => {
        btn.onclick = (e) => {
            const win = e.target.closest('.window');
            toggleWindow(win.id, false);
        };
    });

    /** --- Draggable Logic --- **/
    document.querySelectorAll('.win-header').forEach(header => {
        let isDragging = false;
        let offsetX, offsetY;

        header.onmousedown = (e) => {
            isDragging = true;
            const win = header.closest('.window');
            offsetX = e.clientX - win.offsetLeft;
            offsetY = e.clientY - win.offsetTop;
            header.style.cursor = 'grabbing';
        };

        document.onmousemove = (e) => {
            if (!isDragging) return;
            const win = header.closest('.window');
            win.style.left = (e.clientX - offsetX) + "px";
            win.style.top = (e.clientY - offsetY) + "px";
        };

        document.onmouseup = () => {
            isDragging = false;
            header.style.cursor = 'move';
        };
    });

    // Initial Load
    renderFiles();
</script>

</body>
</html>
